public boolean squirrelPlay(int temp, boolean isSummer) {
    int lowerLimit = 60;
    int upperLimit;

    if (isSummer) {
        upperLimit = 100;
    } else {
        upperLimit = 90;
    }

    return temp >= lowerLimit && temp <= upperLimit;
}

