Code:
public boolean twoTwo(int[] nums) {
    int i = 0, j = 0;
    while (j < nums.length) {
        if (j - i + 1 > 2) {
            i++;
        }
        if (nums[j] == 2 && (j - i + 1 == 2 || nums[j - 1] != 2)) {
            return false;
        }
        j++;
    }
    return true;
}
